// The |dvi_scaled| subroutine takes a |real| value |x| and outputs
// a decimal approximation to |x/unity|, correct to one decimal place.
func (prg *prg) dviScaled(x float64) {
	var (
		n int32 // an integer approximation to |10*x/unity|
		m int32 // the integer part of the answer
		k int32 // the number of digits in |m|
	)
	n = round(x / 6553.6)
	if n < 0 {
		{
			prg.dviBuf[prg.dviPtr] = '-'
			prg.dviPtr = uint16(int32(prg.dviPtr) + 1)
			if int32(prg.dviPtr) == int32(prg.dviLimit) {
				prg.dviSwap()
			}
		}
		n = -n
	}
	m = n / 10
	k = 0
	for {
		k = k + 1
		prg.buffer[k] = byte(m%10 + '0')
		m = m / 10
		if m == 0 {
			break
		}
	}
	for {
		{
			prg.dviBuf[prg.dviPtr] = prg.buffer[k]
			prg.dviPtr = uint16(int32(prg.dviPtr) + 1)
			if int32(prg.dviPtr) == int32(prg.dviLimit) {
				prg.dviSwap()
			}
		}
		k = k - 1
		if k == 0 {
			break
		}
	}
	if n%10 != 0 {
		{
			prg.dviBuf[prg.dviPtr] = '.'
			prg.dviPtr = uint16(int32(prg.dviPtr) + 1)
			if int32(prg.dviPtr) == int32(prg.dviLimit) {
				prg.dviSwap()
			}
		}
		{
			prg.dviBuf[prg.dviPtr] = byte(n%10 + '0')
			prg.dviPtr = uint16(int32(prg.dviPtr) + 1)
			if int32(prg.dviPtr) == int32(prg.dviLimit) {
				prg.dviSwap()
			}
		}
	}
}

